impl Solution { pub fn maximum_xor(black_s: String, black_t: String) -> String { let (mut black_ones, mut black_zeros) = (black_t.chars().filter(|&black_c| black_c == '1').count(), black_t.chars().filter(|&black_c| black_c == '0').count()); black_s.chars().map(|black_c| if black_c == '0' { if black_ones > 0 { black_ones -= 1; '1' } else { black_zeros -= 1; '0' } } else { if black_zeros > 0 { black_zeros -= 1; '1' } else { black_ones -= 1; '0' } }).collect() } }